mapper.select:
SELECT
    (
        SELECT NVL(ROUND(AVG(TX_AMOUNT)), 0)
        FROM FFG_TX_DATA
        WHERE BANK_CODE = #{bankCode}
          AND USER_ID = #{userId}
    ) AS avgTxAmount,
    (
        SELECT COUNT(*)
        FROM FFG_TX_DATA
        WHERE BANK_CODE = #{bankCode}
          AND USER_ID = #{userId}
    ) AS recentTxCount,
    (
        SELECT TX_COUNTRY
        FROM (
                 SELECT TX_COUNTRY, COUNT(*) AS cnt
                 FROM FFG_TX_DATA
                 WHERE BANK_CODE = #{bankCode}
                   AND USER_ID = #{userId}
                   AND TX_COUNTRY IS NOT NULL
                 GROUP BY TX_COUNTRY
                 ORDER BY cnt DESC, TX_COUNTRY
             )
        WHERE ROWNUM = 1
    ) AS mainCountry
FROM DUAL
